mapper.select:
/* wms-ctmaster-zone-sql-oracle.xml - selectZoneList */
SELECT '0' AS CHK , ZN.CTKEY , CT.CTNM , ZN.ZNKEY , ZN.ZNNM , ZN.ZNTYPECD , ZN.INSERTDATE , ZN.INSERTURKEY , ZN.UPDATEDATE , ZN.UPDATEURKEY
ORDER BY ZN.UPDATEDATE DESC

/* wms-ctmaster-zone-sql-oracle.xml - selectZoneDupCheckCount */
SELECT COUNT(1)
  FROM TWORK_MST_ZN
 WHERE CTKEY = #{ctkey}
   AND ZNKEY = #{znkey}

/* wms-ctmaster-zone-sql-oracle.xml - selectZoneUseCheckCount */
SELECT SUM(CNT)
  FROM (
	   SELECT COUNT(1) CNT
		 FROM TWORK_MST_AR
		WHERE CTKEY = #{ctkey}
		  AND ZNKEY = #{znkey}
		UNION
	   SELECT COUNT(1) AS CNT
		 FROM TWORK_MST_LC
		WHERE CTKEY = #{ctkey}
		  AND ZNKEY = #{znkey}
	 )

mapper.insert:
/* wms-ctmaster-zone-sql-oracle.xml - insertZone */
INSERT INTO TWORK_MST_ZN (
  	   CTKEY
	 , ZNKEY
	 , ZNNM
	 , ZNTYPECD
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
	 )
VALUES (
	   #{ctkey}
	 , #{znkey}
	 , #{znnm}
	 , #{zntypecd}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 )

mapper.update:
/* wms-ctmaster-zone-sql-oracle.xml - updateZone */
UPDATE TWORK_MST_ZN
   SET ZNNM = #{znnm}
     , ZNTYPECD = #{zntypecd}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND ZNKEY = #{znkey}

mapper.delete:
/* wms-ctmaster-zone-sql-oracle.xml - deleteZone */
DELETE
  FROM TWORK_MST_ZN
 WHERE CTKEY = #{ctkey}
   AND ZNKEY = #{znkey}
